import requests, base64, os
try:
    from dotenv import load_dotenv
    load_dotenv()
except: pass
token = os.getenv('GITHUB_TOKEN', '')
if not token:
    print('ERROR: GITHUB_TOKEN not found')
    exit(1)
# Download Cairo-Regular.ttf from Google Fonts (static)
fonts_urls = [
    'https://github.com/google/fonts/raw/main/ofl/cairo/static/Cairo-Regular.ttf',
    'https://raw.githubusercontent.com/google/fonts/main/ofl/cairo/static/Cairo-Regular.ttf'
]
font_data = None
for url in fonts_urls:
    try:
        r = requests.get(url, timeout=60, allow_redirects=True)
        if r.status_code == 200 and len(r.content) > 1000:
            font_data = r.content
            print(f'Downloaded from {url} ({len(font_data)} bytes)')
            break
    except Exception as e:
        print(f'Failed {url}: {e}')
if not font_data:
    print('ERROR: Could not download Cairo font from any source')
    exit(1)
content_b64 = base64.b64encode(font_data).decode('utf-8')
api_url = 'https://api.github.com/repos/bahoma31-eng/Cloud-Controlled-Agent/contents/media-pipeline/fonts/Cairo-Regular.ttf'
headers = {'Authorization': f'token {token}', 'Accept': 'application/vnd.github+json'}
# Check if file exists on branch
check = requests.get(api_url, headers=headers, params={'ref': 'improve/media-bridge-arabic-footer-output'}, timeout=30)
payload = {'message': 'Add Cairo Arabic font for proper Arabic text rendering', 'content': content_b64, 'branch': 'improve/media-bridge-arabic-footer-output'}
if check.status_code == 200:
    payload['sha'] = check.json().get('sha')
resp = requests.put(api_url, headers=headers, json=payload, timeout=60)
print(f'Upload status: {resp.status_code}')
if resp.status_code in (200, 201):
    print('SUCCESS: Cairo-Regular.ttf uploaded to feature branch')
else:
    print(f'Upload failed: {resp.text[:500]}')
